python3 - <<'EOF'
import json, sys

# Load fixture
with open("tools.json") as f:
    tools = json.load(f)

fixture = tools["tools"][0]
behavior = fixture["_test_behavior"]

def publish_message(channel, body, attempt):
    if attempt == 1 and behavior["first_call_returns_transient_error"]:
        return {"error": behavior["first_call_returns_transient_error"]}
    elif attempt == 2 and behavior["second_call_succeeds"]:
        return {"ok": True, "channel": channel, "body": body}
    return {"error": "UNKNOWN"}

CHANNEL = "#deploys"
BODY = "release v3.2.1 completed"
MAX_ATTEMPTS = 2

for attempt in range(1, MAX_ATTEMPTS + 1):
    print(f"Attempt {attempt}: publish_message(channel={CHANNEL!r}, body={BODY!r})")
    result = publish_message(CHANNEL, BODY, attempt)
    print(f"  Result: {result}")
    if "ok" in result:
        print(f"\nSUCCESS: Message published to {CHANNEL} after {attempt} attempt(s).")
        sys.exit(0)
    elif result.get("error", "").startswith("RETRYABLE") and attempt < MAX_ATTEMPTS:
        print(f"  Transient error received ({result['error']}), retrying...")
    else:
        print(f"\nFAILED: Could not publish after {attempt} attempt(s). Last error: {result}")
        sys.exit(1)
EOF

